mapper.select:
SELECT t.date AS priceDate, AVG(t.spot_price) AS avgSpotPrice FROM spot_transactions t JOIN companies c ON c.id = t.company_id WHERE t.date BETWEEN #{startDate} AND #{endDate} AND t.spot_price IS NOT NULL
AND t.company_id IN
#{id}
AND c.region_id IN
#{id}
GROUP BY t.date ORDER BY t.date
